sql:
SELECT 
    (SELECT COUNT(alert_id) FROM alerts WHERE alert_type = 'anomaly') AS num_alerts,
    (SELECT COUNT(feedback_id) FROM feedback WHERE user_id = 1) AS num_feedbacks;

SELECT AVG(number_of_samples) AS average_samples_per_user
FROM (
  SELECT user_id, COUNT(sample_id) AS number_of_samples
  FROM text_samples
  GROUP BY user_id
);

SELECT COUNT(*)
FROM predictions
WHERE prediction = 'neg';

SELECT COUNT(DISTINCT user_id) AS number_of_users
FROM text_samples
WHERE source_type = 'forum';

SELECT text_samples.text_excerpt, predictions.prediction
FROM text_samples
INNER JOIN predictions ON text_samples.sample_id = predictions.sample_id;

SELECT SUM(count) 
FROM sentiment_trends 
WHERE trend_date = '2023-10-01';

SELECT COUNT(DISTINCT user_id) AS total_contributors
FROM text_samples
WHERE topic = '<specified_topic>';

external_knowledge:
- "branches of thought" refers to topics in the text samples;
- "blossomed in the past month" refers to text samples submitted in the last 30 days;
- "prevailing emotional climates" refer to the sentiment labels (positive, negative, etc.);
- "average intensity of these sentiments" refers to the average compound score;
- "how many times each climate has been observed" refers to the count of occurrences of each sentiment label within the same topic.
